      { id: 10037, question: "(2023真题)下列关于红霉素的说法，正确的是？", options: ["属于β-内酰胺类", "对支原体有效", "主要经肾脏排泄", "对厌氧菌无效"], answer: 1, hint: "红霉素特点", explanation: "红霉素属于大环内酯类抗生素，对支原体、衣原体等非典型病原体有效，主要经肝脏代谢，对部分厌氧菌也有作用。" },
      { id: 10038, question: "(2022真题)喹诺酮类抗生素的作用机制是？", options: ["抑制细菌细胞壁合成", "抑制细菌蛋白质合成", "抑制细菌DNA复制", "影响细菌细胞膜通透性"], answer: 2, hint: "喹诺酮类作用机制", explanation: "喹诺酮类抗生素通过抑制细菌DNA旋转酶，阻止细菌DNA复制和转录，发挥杀菌作用。" },
      { id: 10039, question: "(2023模拟)下列哪种药物属于磺胺类抗生素？", options: ["青霉素", "头孢曲松", "磺胺嘧啶", "红霉素"], answer: 2, hint: "磺胺类抗生素", explanation: "磺胺嘧啶是经典的磺胺类抗生素，通过抑制细菌叶酸合成发挥抗菌作用。" },
      { id: 10040, question: "(2023真题)甲硝唑主要用于治疗？", options: ["真菌感染", "病毒感染", "厌氧菌感染", "支原体感染"], answer: 2, hint: "甲硝唑适应症", explanation: "甲硝唑是治疗厌氧菌感染的首选药物之一，也可用于治疗滴虫病、阿米巴病等。" },
      { id: 10041, question: "(2022模拟)下列关于万古霉素的说法，正确的是？", options: ["对革兰氏阴性菌有效", "主要用于治疗MRSA感染", "口服吸收好", "没有肾毒性"], answer: 1, hint: "万古霉素特点", explanation: "万古霉素对革兰氏阳性菌有效，尤其是耐甲氧西林金黄色葡萄球菌（MRSA），口服吸收差，有一定的肾毒性。" },
      { id: 10042, question: "(2023真题)氯霉素的主要不良反应是？", options: ["耳毒性", "肾毒性", "骨髓抑制", "胃肠道反应"], answer: 2, hint: "氯霉素不良反应", explanation: "氯霉素的主要不良反应是骨髓抑制，可能导致再生障碍性贫血，使用时需严格监测血常规。" },
      { id: 10043, question: "(2022真题)四环素类抗生素的主要不良反应不包括？", options: ["牙齿变色", "胃肠道反应", "肝损害", "耳毒性"], answer: 3, hint: "四环素类不良反应", explanation: "四环素类抗生素的主要不良反应包括牙齿变色、胃肠道反应、肝损害等，耳毒性不是其主要不良反应。" },
      { id: 10044, question: "(2023模拟)下列关于利福平的说法，正确的是？", options: ["只对细菌有效", "是肝药酶抑制剂", "主要用于抗结核治疗", "口服吸收差"], answer: 2, hint: "利福平特点", explanation: "利福平是抗结核药物，对结核分枝杆菌有效，是肝药酶诱导剂，口服吸收好。" },
      { id: 10045, question: "(2023真题)抗真菌药物的分类不包括？", options: ["唑类", "棘白菌素类", "青霉素类", "多烯类"], answer: 2, hint: "抗真菌药分类", explanation: "抗真菌药主要分为唑类、棘白菌素类、多烯类等，青霉素类是抗生素，不是抗真菌药。" }
