      { id: 10157, question: "(2023真题)处方药的特点是？", options: ["不需要处方即可购买", "可以在药店随意购买", "必须凭医师处方购买", "不需要药师审核"], answer: 2, hint: "处方药特点", explanation: "处方药必须凭执业医师或执业助理医师的处方才能购买和使用，需要药师审核后方可调配。" },
      { id: 10158, question: "(2022真题)非处方药的特点是？", options: ["需要处方", "不需要处方即可购买", "只能在医院购买", "没有说明书"], answer: 1, hint: "非处方药特点", explanation: "非处方药不需要处方即可购买，消费者可以自行判断和使用，有详细的说明书指导。" },
      { id: 10159, question: "(2023模拟)药品的批准文号格式是？", options: ["国药准字+字母+6位数字", "国药准字+字母+8位数字", "国药准字+数字+字母", "不需要批准文号"], answer: 1, hint: "药品批准文号格式", explanation: "药品批准文号格式为国药准字+字母+8位数字，字母代表药品类别。" },
      { id: 10160, question: "(2023真题)下列关于药品不良反应的说法，正确的是？", options: ["药品不良反应只发生在用药后立即", "药品不良反应可以预测", "药品不良反应是指在正常用法用量下出现的有害反应", "药品不良反应不需要报告"], answer: 2, hint: "药品不良反应", explanation: "药品不良反应是指在正常用法用量下出现的与用药目的无关的有害反应，需要及时报告。" },
      { id: 10161, question: "(2022模拟)药品的不良反应报告制度的目的是？", options: ["惩罚药品生产企业", "保障用药安全", "增加药品销量", "减少药品使用"], answer: 1, hint: "不良反应报告目的", explanation: "药品不良反应报告制度的目的是及时发现和控制药品风险，保障公众用药安全。" }
