      { id: 10197, question: "(2023真题)下列关于药物不良反应的说法，正确的是？", options: ["不良反应都是有害的", "不良反应可以避免", "不良反应是正常现象", "不良反应需要报告"], answer: 3, hint: "不良反应报告", explanation: "药物不良反应需要及时报告，以便监测和控制药物风险。" },
      { id: 10198, question: "(2022真题)下列关于药物不良反应的说法，错误的是？", options: ["不良反应可能危及生命", "不良反应需要处理", "不良反应不需要关注", "不良反应可能影响治疗"], answer: 2, hint: "不良反应的重要性", explanation: "药物不良反应需要关注和处理，可能危及生命或影响治疗效果。" },
      { id: 10199, question: "(2023模拟)严重不良反应不包括？", options: ["过敏性休克", "肝肾功能损害", "轻微头痛", "血液系统损害"], answer: 2, hint: "严重不良反应", explanation: "严重不良反应包括过敏性休克、肝肾功能损害、血液系统损害等，轻微头痛不属于严重不良反应。" },
      { id: 10200, question: "(2023真题)药物不良反应的处理原则不包括？", options: ["立即停药", "对症处理", "继续用药", "报告不良反应"], answer: 2, hint: "不良反应处理", explanation: "药物不良反应的处理原则包括立即停药、对症处理、报告不良反应等，继续用药会加重不良反应。" },
      { id: 10201, question: "(2022模拟)下列关于药物不良反应监测的说法，正确的是？", options: ["不需要监测", "只监测严重不良反应", "需要持续监测", "只监测新上市药物"], answer: 2, hint: "不良反应监测", explanation: "药物不良反应需要持续监测，不仅包括严重不良反应，也包括一般不良反应，所有药物都需要监测。" },
      { id: 10202, question: "(2023真题)药物不良反应报告的意义不包括？", options: ["保障用药安全", "促进药物研发", "惩罚生产企业", "提高医疗质量"], answer: 2, hint: "不良反应报告意义", explanation: "药物不良反应报告的意义包括保障用药安全、促进药物研发、提高医疗质量等，不是为了惩罚生产企业。" },
      { id: 10203, question: "(2022真题)下列关于药物不良反应的说法，正确的是？", options: ["只有处方药会引起不良反应", "只有西药会引起不良反应", "所有药物都可能引起不良反应", "中药不会引起不良反应"], answer: 2, hint: "不良反应的普遍性", explanation: "所有药物都可能引起不良反应，包括处方药、非处方药、中药和西药。" },
      { id: 10204, question: "(2023模拟)药物不良反应的发生率约为？", options: ["1%以下", "1-10%", "50%以上", "100%"], answer: 1, hint: "不良反应发生率", explanation: "药物不良反应的发生率约为1-10%，不同药物的发生率有所不同。" },
      { id: 10205, question: "(2023真题)下列关于药物不良反应的说法，错误的是？", options: ["不良反应可以预防", "不良反应可以减轻", "不良反应可以完全避免", "不良反应需要管理"], answer: 2, hint: "不良反应的不可避免性", explanation: "虽然可以预防和减轻药物不良反应，但不能完全避免，需要合理管理。" }
