      { id: 10234, question: "(2023模拟)处方的书写要求不包括？", options: ["字迹清晰", "内容完整", "签名规范", "使用铅笔"], answer: 3, hint: "处方书写要求", explanation: "处方书写要求字迹清晰、内容完整、签名规范，不能使用铅笔。" },
      { id: 10235, question: "(2023真题)下列关于处方的说法，正确的是？", options: ["处方可以随意涂改", "处方不需要审核", "处方是医疗文书", "处方不需要保存"], answer: 2, hint: "处方性质", explanation: "处方是医疗文书，需要审核和保存，不能随意涂改。" }
