      { id: 10254, question: "(2023真题)成本-效益分析的特点是？", options: ["用货币单位衡量效益", "用非货币单位衡量效益", "不考虑成本", "不考虑效益"], answer: 0, hint: "成本-效益分析", explanation: "成本-效益分析用货币单位衡量效益，便于不同项目之间的比较。" },
      { id: 10255, question: "(2022真题)药物经济学的应用不包括？", options: ["药品定价", "医保目录制定", "药物研发决策", "药物颜色选择"], answer: 3, hint: "药物经济学应用", explanation: "药物经济学应用于药品定价、医保目录制定、药物研发决策等，不涉及药物颜色选择。" },
      { id: 10256, question: "(2023模拟)下列关于药物经济学的说法，正确的是？", options: ["药物经济学不重要", "药物经济学只关注成本", "药物经济学关注成本与效果", "药物经济学不关注患者"], answer: 2, hint: "药物经济学核心", explanation: "药物经济学关注药物的成本与效果，以最小的成本获得最大的健康效益。" },
      { id: 10257, question: "(2023真题)下列关于药物经济学的说法，错误的是？", options: ["药物经济学可以优化资源配置", "药物经济学可以帮助决策", "药物经济学不需要数据", "药物经济学需要科学方法"], answer: 2, hint: "药物经济学的科学性", explanation: "药物经济学需要大量的数据支持，采用科学的方法进行分析。" },
      { id: 10258, question: "(2022真题)药物经济学的研究目的是？", options: ["降低药品价格", "提高药品质量", "优化药物治疗方案", "增加药品销量"], answer: 2, hint: "药物经济学目的", explanation: "药物经济学的研究目的是优化药物治疗方案，提高资源利用效率。" },
      { id: 10259, question: "(2023模拟)药物经济学的评价指标不包括？", options: ["成本", "效果", "效益", "颜色"], answer: 3, hint: "药物经济学指标", explanation: "药物经济学的评价指标包括成本、效果、效益等，颜色不是评价指标。" },
      { id: 10260, question: "(2023真题)下列关于药物经济学的说法，正确的是？", options: ["药物经济学只适用于发达国家", "药物经济学只关注短期效果", "药物经济学可以指导临床决策", "药物经济学没有实际意义"], answer: 2, hint: "药物经济学的应用价值", explanation: "药物经济学可以指导临床决策，帮助选择更经济有效的治疗方案。" },
      { id: 10261, question: "(2022模拟)成本-效用分析的特点是？", options: ["用生命质量调整年衡量效果", "用货币单位衡量效果", "不考虑生命质量", "不考虑成本"], answer: 0, hint: "成本-效用分析", explanation: "成本-效用分析用生命质量调整年（QALY）衡量效果，考虑生命质量。" },
      { id: 10262, question: "(2023真题)药物经济学在药品研发中的作用不包括？", options: ["评估研发价值", "优化研发方向", "确定药物颜色", "预测市场前景"], answer: 2, hint: "药物经济学在研发中的作用", explanation: "药物经济学在药品研发中可以评估研发价值、优化研发方向、预测市场前景等，不涉及药物颜色。" },
      { id: 10263, question: "(2022真题)药物经济学在医保目录中的作用不包括？", options: ["评估药物性价比", "确定报销范围", "制定报销比例", "确定药物形状"], answer: 3, hint: "药物经济学在医保中的作用", explanation: "药物经济学在医保目录中可以评估药物性价比、确定报销范围和比例等，不涉及药物形状。" },
      { id: 10264, question: "(2023模拟)下列关于药物经济学的说法，正确的是？", options: ["药物经济学只关注药物", "药物经济学不关注患者", "药物经济学关注整体治疗", "药物经济学不关注成本"], answer: 2, hint: "药物经济学的整体性", explanation: "药物经济学关注整体治疗方案，考虑患者的整体健康效益。" },
      { id: 10265, question: "(2023真题)药物经济学的发展趋势不包括？", options: ["方法学完善", "应用范围扩大", "数据质量提高", "只关注成本"], answer: 3, hint: "药物经济学发展趋势", explanation: "药物经济学的发展趋势包括方法学完善、应用范围扩大、数据质量提高等，不是只关注成本。" }
